mapper.sql:
WHERE 1 = 1

    AND e.signal_date  >=  #{start}


    AND e.signal_date  <=  #{end}


    AND (
        e.stock_code LIKE CONCAT('%', #{keyword}, '%')
        OR e.stock_name LIKE CONCAT('%', #{keyword}, '%')
    )


    AND e.increase_amount  >=  #{minIncreaseAmount}


    AND e.signal_score  >=  #{minSignalScore}


    AND COALESCE(s.backtest_score, 0)  >=  #{minBacktestScore}


    AND e.has_same_day_decrease = #{hasSameDayDecrease}

mapper.select:
SELECT trade_date AS tradeDate, open_price AS openPrice, close_price AS closePrice, high_price AS highPrice, low_price AS lowPrice FROM stock_daily_bar WHERE stock_code = #{stockCode}
AND trade_date >= #{startDate}
AND trade_date <= #{endDate}
ORDER BY trade_date

SELECT trade_date AS tradeDate, stock_code AS stockCode, stock_name AS stockName, change_type AS changeType, ABS(total_price) AS totalPrice, price AS price, changer_name AS changerName, changer_position AS changerPosition FROM daily_stock_change WHERE stock_code = #{stockCode}
AND trade_date >= #{startDate}
AND trade_date <= #{endDate}
ORDER BY trade_date
